mapper.sql:
select t1.id,t1.user_id,t1.topic_id,t1.role,t1.order_num,t1.status, t1.mute_end_time, t1.join_time, t1.start_time, t1.end_time, t1.type, t1.inter_num,t1.block_remark,
       t1.remark,t1.creator,t1.create_time,t1.updater,t1.update_time
from cm_topic_member t1 left join promotion_kefu_conversation t2 on (t1.user_id = t2.user_id or t1.user_id = t2.receiver_id)

mapper.select:

where t1.deleted=0
     and t1.topic_id = #{reqvo.topicId}
order by t2.last_message_time DESC

select t1.id,t1.user_id,t1.topic_id,t1.role,t1.order_num,t1.status, t1.mute_end_time, t1.join_time, t1.start_time, t1.end_time, t1.type, t1.inter_num,t1.block_remark,
       t1.remark,t1.creator,t1.create_time,t1.updater,t1.update_time,t2.nickname,t2.mobile,t2.name,t2.avatar
from cm_topic_member t1 left join member_user t2 on t1.user_id = t2.id
where 1=1 and t1.role=0
 and t1.topic_id = #{reqvo.topicId}
 and t1.user_id = #{reqvo.userId}

  and (t2.nickname like concat('%', #{reqvo.nickname}, '%') or t2.mobile like concat('%', #{reqvo.nickname}, '%')
       or t2.id like concat('%', #{reqvo.nickname}, '%')  or t2.name like concat('%', #{reqvo.nickname}, '%')
      )

 and t2.mobile like concat('%', #{reqvo.mobile}, '%')

    AND DATE(t1.start_time) BETWEEN #{reqvo.beginTime} AND #{reqvo.finishTime}

order by t1.start_time DESC

select t1.id,t1.user_id,t1.topic_id,t1.role,t1.order_num,t1.status, t1.mute_end_time, t1.join_time, t1.start_time, t1.end_time, t1.type, t1.inter_num,t1.block_remark, t1.remark,t1.creator,t1.create_time,t1.updater,t1.update_time,t2.nickname,t2.name,t2.mobile,t2.avatar from cm_topic_member t1 left join member_user t2 on t1.user_id = t2.id where 1=1 and t1.topic_id = #{reqvo.topicId}
and (t2.nickname like concat('%', #{reqvo.nickname}, '%') or t2.mobile like concat('%', #{reqvo.nickname}, '%') or t2.id like concat('%', #{reqvo.nickname}, '%') or t2.name like concat('%', #{reqvo.nickname}, '%') )
order by t1.start_time DESC

select t1.id,t1.user_id,t1.topic_id,t1.role,t1.order_num,t1.status, t1.mute_end_time, t1.join_time, t1.start_time, t1.end_time, t1.type, t1.inter_num,t1.block_remark,
t1.remark,t1.creator,t1.create_time,t1.updater,t1.update_time,t2.nickname,t2.name,t2.mobile,t2.avatar
from cm_topic_member t1 left join member_user t2 on t1.user_id = t2.id
where t1.role=0
 and t1.topic_id = #{reqvo.topicId}

    and (t2.nickname like concat('%', #{reqvo.nickname}, '%') or t2.mobile like concat('%', #{reqvo.nickname}, '%')
    or t2.id like concat('%', #{reqvo.nickname}, '%')  or t2.name like concat('%', #{reqvo.nickname}, '%')
    )


    AND DATE(t1.start_time) BETWEEN #{reqvo.beginTime} AND #{reqvo.finishTime}

order by t1.start_time DESC
